$monthList = list("Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec");
$date = entity\attribute('date');
$mIdx= datetime\month($date);
$month = $monthList[$mIdx-1];
$year = datetime\year($date);

$currentMonth = datetime\month(datetime\today());
$currentYear = datetime\year(datetime\today());

// Validation if payroll running for today 
ifThen($mIdx==$currentMonth && $year==$currentYear, 
    recordService\throwForbidden('You can\'t create payroll for current month');
);


// Validation if duplicate entry detected for same employee and for same month
$recId = record\findOne('CEmployeePayroll', 
            'createdAt',asc, 
            'year', $year,
            'month',$month,
            'employeeId',entity\attribute('employeeId'),
            'assignedUserId', entity\attribute('assignedUserId')
        );

output\printLine($recId);
ifThen($recId, 
    recordService\throwForbidden(
            string\concatenate('Duplicate entry detected for ', entity\attribute('assignedUserName'));
        );
);
